      <InputField label="Reference" value={viewport.referenceNote || ''} onChange={(value) => updateViewport({ referenceNote: value })} />
      <InputField
        label="Frame Mode"
        value={sheet.layoutTemplate === 'auto' ? (viewport.lockAutoLayout ? 'Manual' : 'Auto') : 'Manual (sheet)'}
        readOnly
      />
      {sheet.layoutTemplate === 'auto' && (
        <button className={styles.actionBtn} onClick={toggleLayoutMode}>
          {viewport.lockAutoLayout ? 'Use auto layout' : 'Convert to manual frame'}
        </button>
      )}
      <div className={styles.subtitle}>Frame</div>
      <InputField label="X" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.x)} onChange={(value) => updateViewport({ x: u.fromDisplay(value) })} />
      <InputField label="Y" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.y)} onChange={(value) => updateViewport({ y: u.fromDisplay(value) })} />
      <InputField label="Width" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.width)} onChange={(value) => updateViewport({ width: Math.max(20, u.fromDisplay(value)) })} />
      <InputField label="Height" type="number" suffix={u.suffix} value={u.toDisplay(displayedViewport.height)} onChange={(value) => updateViewport({ height: Math.max(20, u.fromDisplay(value)) })} />
      <InputField label="Scale 1:" type="number" value={Math.round(viewport.scale)} onChange={(value) => updateViewport({ scale: Math.max(1, Math.round(value)) })} />
      <InputField label="Rotation" type="number" suffix="°" step={1} value={displayedViewport.rotation || 0} onChange={(value) => updateViewport({ rotation: ((value % 360) + 360) % 360 })} />
    </div>
  );
}

function FloorProperties({ floor, dispatch, onDuplicate, onDelete, canDelete, u }) {
  const updateFloor = (updates) => {
    dispatch({ type: 'FLOOR_UPDATE', floor: { id: floor.id, ...updates } });
  };

  return (
    <div>
      <div className={styles.title}>Floor</div>
      <InputField
        label="Name"
        value={floor.name}
        onChange={(value) => updateFloor({ name: value })}
      />
      <InputField
        label="Level Index"
        type="number"
        step={1}
        value={getFloorLevelIndex(floor)}
        onChange={(value) => updateFloor({ levelIndex: Math.round(value) })}
      />
      <InputField
        label="Elevation"
        type="number"
        suffix={u.suffix}
        step={u.step(100)}
        value={u.toDisplay(getFloorElevation(floor))}
        onChange={(value) => updateFloor({ elevation: u.fromDisplay(value) })}
      />
      <InputField
        label="Floor to Floor"
        type="number"
        suffix={u.suffix}
        step={u.step(100)}
        value={u.toDisplay(getFloorToFloorHeight(floor))}
        onChange={(value) => updateFloor({ floorToFloorHeight: Math.max(100, u.fromDisplay(value)) })}
      />
      <div className={styles.subtitle}>Contents</div>
      <InputField label="Walls" value={floor.walls.length} readOnly />
      <InputField label="Rooms" value={floor.rooms.length} readOnly />
      <InputField label="Doors" value={floor.doors.length} readOnly />
      <InputField label="Windows" value={floor.windows.length} readOnly />
      <InputField label="Columns" value={(floor.columns || []).length} readOnly />
      <InputField label="Beams" value={(floor.beams || []).length} readOnly />
      <InputField label="Stairs" value={(floor.stairs || []).length} readOnly />
      <InputField label="Slabs" value={(floor.slabs || []).length} readOnly />
      <button
        className={styles.actionBtn}
        onClick={() => onDuplicate(floor)}
      >
        Duplicate floor
      </button>
      <button
        className={styles.deleteBtn}
        onClick={() => onDelete(floor)}
        disabled={!canDelete}
      >
        Delete floor
      </button>
    </div>
  );
}

