          <input
            className={styles.colorPicker}
            type="color"
            value={room.color}
            onChange={(e) => updateRoom({ color: e.target.value })}
            aria-label="Room color"
          />
          <input
            className={styles.colorHexInput}
            type="text"
            value={room.color}
            onChange={(e) => {
              const hex = e.target.value;
              if (/^#[0-9a-fA-F]{6}$/.test(hex)) updateRoom({ color: hex });
