function useUnits() {
  const [unit, setUnit] = useState('mm');
  const isMm = unit === 'mm';
  return {
    unit,
    setUnit,
    suffix: isMm ? 'mm' : 'm',
    toDisplay: (mm) => isMm ? +mm.toFixed(1) : +(mm / 1000).toFixed(4),
    fromDisplay: (v) => isMm ? v : v * 1000,
    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
  };
}

function WallDrawingInput({ start, dispatch, editorDispatch, activeFloorId, u, selectNewWall }) {
  const [nsDir, setNsDir] = useState('N');
  const [ewDir, setEwDir] = useState('E');
  const [degrees, setDegrees] = useState('');
  const [minutes, setMinutes] = useState('');
  const [lengthVal, setLengthVal] = useState('');
  const lengthRef = useRef(null);

  const handleConfirm = () => {
    const deg = parseInt(degrees, 10) || 0;
    const min = parseInt(minutes, 10) || 0;
    const len = u.fromDisplay(parseFloat(lengthVal) || 0);

    if (len < MIN_WALL_LENGTH) return;
    if (deg < 0 || deg > 90 || min < 0 || min > 59) return;

    const angle = surveyorBearingToSvgAngle(nsDir, deg, min, ewDir);
    const endPt = endpointFromBearing(start, len, angle);
    const wall = createWall(start, endPt);

    dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });
    if (selectNewWall) {
      editorDispatch({ type: 'SELECT_OBJECT', id: wall.id, objectType: 'wall' });
    } else {
      editorDispatch({
        type: 'UPDATE_TOOL_STATE',
        payload: { start: endPt, startAttachment: null, preview: null },
      });
    }

    setDegrees('');
    setMinutes('');
    setLengthVal('');
    setTimeout(() => lengthRef.current?.focus(), 0);
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleConfirm();
    }
  };

  return (
    <div>
      <div className={styles.title}>Drawing Wall</div>
      <div style={{ fontSize: 12, color: 'var(--color-text-secondary)', marginBottom: 'var(--space-sm)' }}>
        Start: ({u.toDisplay(start.x)}, {u.toDisplay(start.y)}) {u.suffix}
      </div>

      <div className={styles.subtitle}>Bearing</div>
      <div className={styles.bearingRow}>
        <select className={styles.bearingSelect} value={nsDir} onChange={(e) => setNsDir(e.target.value)}>
          <option value="N">N</option>
          <option value="S">S</option>
        </select>
        <input
          className={styles.bearingInput}
          type="number"
          min={0}
          max={90}
          placeholder="0"
          value={degrees}
          onChange={(e) => setDegrees(e.target.value)}
          onKeyDown={handleKeyDown}
        />
        <span className={styles.bearingSymbol}>°</span>
        <input
          className={styles.bearingInput}
          type="number"
          min={0}
          max={59}
          placeholder="0"
          value={minutes}
          onChange={(e) => setMinutes(e.target.value)}
          onKeyDown={handleKeyDown}
        />
        <span className={styles.bearingSymbol}>′</span>
        <select className={styles.bearingSelect} value={ewDir} onChange={(e) => setEwDir(e.target.value)}>
          <option value="E">E</option>
          <option value="W">W</option>
        </select>
      </div>

      <div className={styles.subtitle}>Length</div>
      <input
        ref={lengthRef}
        className={styles.bearingInput}
        style={{ width: '100%', textAlign: 'left', padding: '0 8px', marginBottom: 'var(--space-sm)' }}
        type="number"
        min={0}
        step={u.step(100)}
        placeholder={`0 ${u.suffix}`}
        value={lengthVal}
        onChange={(e) => setLengthVal(e.target.value)}
        onKeyDown={handleKeyDown}
      />

      <button className={styles.confirmBtn} onClick={handleConfirm}>
        Create Wall (Enter)
      </button>
    </div>
  );
}

function SheetExportMenu({ sheet, editorDispatch }) {
  const [open, setOpen] = useState(false);
  const rootRef = useRef(null);
  const pngOptions = [
    { label: 'PNG 150 DPI', dpi: 150 },
    { label: 'PNG 300 DPI', dpi: 300 },
    { label: 'PNG 600 DPI', dpi: 600 },
  ];

  useEffect(() => {
    if (!open) return undefined;

    const handleMouseDown = (event) => {
      if (rootRef.current && !rootRef.current.contains(event.target)) {
        setOpen(false);
      }
    };

    document.addEventListener('mousedown', handleMouseDown);
    return () => document.removeEventListener('mousedown', handleMouseDown);
  }, [open]);

  const handleExport = async (kind, options = {}) => {
    if (!sheet) return;
    try {
      if (kind === 'pdf') {
        await exportActiveSheetAsPdf(
          sheet.title || sheet.drawingName || 'sheet',
          sheet.paperSize
        );
        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Exported sheet as PDF.' });
      } else {
        await exportActiveSheetAsPng(
          sheet.title || sheet.drawingName || 'sheet',
          options
        );
        const dpiLabel = options.dpi ? ` (${options.dpi} DPI)` : '';
        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: `Exported sheet as PNG${dpiLabel}.` });
      }
    } catch (error) {
      editorDispatch({
        type: 'SET_STATUS_MESSAGE',
        message: error.message || `${kind.toUpperCase()} export failed.`,
      });
    } finally {
      setOpen(false);
    }
  };

  return (
    <div className={styles.exportMenu} ref={rootRef}>
      <button
        className={styles.exportMenuTrigger}
        type="button"
        onClick={() => setOpen((value) => !value)}
      >
        Export sheet
        <span className={styles.exportMenuChevron}>{open ? '▴' : '▾'}</span>
      </button>
      {open && (
        <div className={styles.exportMenuList}>
          <button
            className={styles.exportMenuItem}
            type="button"
            onClick={() => handleExport('pdf')}
          >
            PDF
          </button>
          {pngOptions.map((option) => (
            <button
              key={option.dpi}
              className={styles.exportMenuItem}
              type="button"
              onClick={() => handleExport('png', { dpi: option.dpi })}
            >
              {option.label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

