            className={styles.colorHexInput}
            type="text"
            value={room.color}
            onChange={(e) => {
              const hex = e.target.value;
              if (/^#[0-9a-fA-F]{6}$/.test(hex)) updateRoom({ color: hex });
            }}
            onBlur={(e) => {
              let hex = e.target.value.trim();
              if (!hex.startsWith('#')) hex = '#' + hex;
              if (/^#[0-9a-fA-F]{6}$/.test(hex)) updateRoom({ color: hex });
            }}
          />
        </div>
      </div>
    </div>
  );
}

