 49→export function nextSectionLabel(existingCuts = []) {
 50→  const usedLetters = new Set(
 51→    existingCuts
 52→      .map(c => {
 53→        const match = c.label?.match(/^Section\s+([A-Z])-\1$/);
 54→        return match ? match[1] : null;
 55→      })
 56→      .filter(Boolean)
 57→  );
 58→  for (let i = 0; i < 26; i++) {
 59→    const letter = String.fromCharCode(65 + i);
 60→    if (!usedLetters.has(letter)) return `Section ${letter}-${letter}`;
 61→  }
 62→  return `Section ${existingCuts.length + 1}`;
 63→}
