11→export function getAnnotationDisplayLabel(annotation) {
12→  if (!annotation || annotation.type !== 'dimension') {
13→    return annotation?.id || 'Annotation';
14→  }
15→
16→  const dx = annotation.endPoint.x - annotation.startPoint.x;
17→  const dy = annotation.endPoint.y - annotation.startPoint.y;
18→  let measurement = Math.hypot(dx, dy);
19→
20→  if (annotation.mode === 'horizontal') measurement = Math.abs(dx);
21→  if (annotation.mode === 'vertical') measurement = Math.abs(dy);
22→
23→  return annotation.textOverride?.trim() || `Dim ${formatMeasurement(measurement)}`;
24→}
